{
  "query": "Find tables relevant for user risk analysis: sign-in logs, authentication failures, risky sign-ins, alerts, and endpoint/security alerts (e.g., SigninLogs, SigninTable, SecurityAlert, AuditLogs, OfficeActivity, Heartbeat, DeviceEvents). Return their schemas."
}

{
  "query": "let start = ago(30d);
// Latest risk per user
let riskyUsers = AADRiskyUsers
| where TimeGenerated >= start
| summarize arg_max(TimeGenerated, RiskLevel, RiskState, RiskLastUpdatedDateTime, UserDisplayName) by UserPrincipalName, UserId;
// Aggregate user risk events
let userRiskEvents = AADUserRiskEvents
| where TimeGenerated >= start
| summarize risk_events = count(), high_events = countif(RiskLevel == "high"), medium_events = countif(RiskLevel == "medium"), low_events = countif(RiskLevel == "low") by UserPrincipalName, UserId;
// Sign-in risk signals
let signInRisks = SigninLogs
| where TimeGenerated >= start
| summarize signins = count(), risky_signins = countif(IsRisky == true or RiskLevelDuringSignIn == "high" or RiskLevel == "high") by UserPrincipalName, UserId;
// Alerts that list a compromised entity (user)
let userAlerts = SecurityAlert
| where TimeGenerated >= start
| where isnotempty(CompromisedEntity)
| summarize alerts = count() by CompromisedEntity;

riskyUsers
| join kind=leftouter userRiskEvents on UserPrincipalName
| join kind=leftouter signInRisks on UserPrincipalName
| join kind=leftouter (userAlerts) on $left.UserPrincipalName == $right.CompromisedEntity
| extend RiskLevel = todynamic(RiskLevel) // safe-cast
| extend risk_value = case(RiskLevel=="high",50, RiskLevel=="medium",20, RiskLevel=="low",10, 0)
| extend ev = coalesce(risk_events, 0), he = coalesce(high_events, 0), me = coalesce(medium_events, 0), le = coalesce(low_events, 0), rs = coalesce(risky_signins,0), al = coalesce(alerts,0), si = coalesce(signins,0)
| extend score = risk_value + ev*3 + rs*7 + al*12 + he*5 + me*2
| project UserPrincipalName, UserDisplayName, UserId, RiskLevel, RiskState, RiskLastUpdatedDateTime, risk_events=ev, high_events=he, medium_events=me, low_events=le, signins=si, risky_signins=rs, alerts=al, score
| order by score desc
| take 3
",
  "workspaceId": ""
}

